Here are the public test cases for feature2_1_parse_time:
{
  "description": "Parse a wall-clock time string into its hour, minute, day-shift (yesterday/today/tomorrow) and clock convention (24-hour vs 12-hour), including the 24:00 boundary; reject malformed and out-of-range values.",
  "cases": [
    {
      "input": {
        "action": "parse_time",
        "text": "9:42"
      },
      "expected_output": "hour=9\nminute=42\nday_shift=0\nclock=24h\n"
    },
    {
      "input": {
        "action": "parse_time",
        "text": "1:45pm"
      },
      "expected_output": "hour=13\nminute=45\nday_shift=0\nclock=12h\n"
    },
    {
      "input": {
        "action": "parse_time",
        "text": "<3:43"
      },
      "expected_output": "hour=3\nminute=43\nday_shift=-1\nclock=24h\n"
    },
    {
      "input": {
        "action": "parse_time",
        "text": "24:00"
      },
      "expected_output": "hour=0\nminute=0\nday_shift=1\nclock=24h\n"
    }
  ]
}

