Here are the public test cases for feature5_1_extract_tags:
{
  "description": "Extract all hashtags from one or more lines of free text, returning them lowercased, de-duplicated and sorted; a tag is a '#' followed by letters, digits or underscores and ends at the first other character.",
  "cases": [
    {
      "input": {
        "action": "extract_tags",
        "lines": [
          "Hello #world, I feel #great #TODAY"
        ]
      },
      "expected_output": "tags=#great,#today,#world\n"
    },
    {
      "input": {
        "action": "extract_tags",
        "lines": [
          "Hello #world, I feel",
          "#GREAT-ish today #123_test!"
        ]
      },
      "expected_output": "tags=#123_test,#great,#world\n"
    }
  ]
}

Here are the public test cases for feature5_2_match_tag:
{
  "description": "Test whether a set of extracted tags contains a query tag. An exact query matches a whole tag; a query ending in '...' matches any tag that starts with the given prefix (fuzzy match).",
  "cases": [
    {
      "input": {
        "action": "match_tag",
        "lines": [
          "Hello #world, I feel #GREAT-ish today #123_test!"
        ],
        "query": "#123_..."
      },
      "expected_output": "tags=#123_test,#great,#world\nquery=#123_...\nmatches=true\n"
    },
    {
      "input": {
        "action": "match_tag",
        "lines": [
          "Hello #world, I feel #GREAT-ish today #123_test!"
        ],
        "query": "worl"
      },
      "expected_output": "tags=#123_test,#great,#world\nquery=worl\nmatches=false\n"
    },
    {
      "input": {
        "action": "match_tag",
        "lines": [
          "Hello #world, I feel #GREAT-ish today #123_test!"
        ],
        "query": "WoRl..."
      },
      "expected_output": "tags=#123_test,#great,#world\nquery=WoRl...\nmatches=true\n"
    }
  ]
}

