Here are the public test cases for feature9_3_hypothetical_total:
{
  "description": "Compute the total tracked time as if every open range were closed at a given reference timestamp, and report whether an open range was actually counted (i.e. the record is ongoing). Open ranges only count if their record is the reference day or the day before.",
  "cases": [
    {
      "input": {
        "action": "hypothetical_total",
        "until": "2020-01-01T05:06:59-0000",
        "text": "2020-01-01\n    2h14m\n    <23:00 - 4:00\n    5:07 - ?"
      },
      "expected_output": "total_minutes=434\nongoing=false\n"
    },
    {
      "input": {
        "action": "hypothetical_total",
        "until": "2020-01-01T10:48:13-0000",
        "text": "2020-01-01\n    2h14m\n    <23:00 - 4:00\n    5:07 - ?"
      },
      "expected_output": "total_minutes=775\nongoing=true\n"
    }
  ]
}
